# This file was generated by claude and is only verified with black-box testing
"""Auto-generate lua/config/explicit.lua from feature Config definitions.

Reads each feature's .Config block(s) as the source of truth and assembles
them into explicit.lua with all BRC references resolved to literal values.

Usage: python3 build/generate_explicit_config.py
"""

import re
import sys
from pathlib import Path
from typing import Dict, List, Optional, Tuple

base_dir = Path(__file__).parent.parent
features_dir = base_dir / "lua" / "features"
constants_file = base_dir / "lua" / "core" / "constants.lua"
config_file = base_dir / "lua" / "core" / "config.lua"
hotkey_file = base_dir / "lua" / "core" / "hotkey.lua"
init_file = base_dir / "rc" / "init.txt"
output_file = base_dir / "lua" / "config" / "explicit.lua"

HEADER = """\
--- Explicit config: All config values from all features listed explicitly, set to defaults
--- Auto-generated by build/generate_explicit_config.py — do not edit manually.
--- To regenerate: python3 build/generate_explicit_config.py
--- Large feature config sections are at the end
--- @warning Since this lives at the top of the RC, it can't reference constants.lua or util/*.lua
---   So it must hardcode values like keycodes, where feature configs get to use BRC.KEYS, etc
"""

# Features to exclude (incomplete / not in init.txt)
EXCLUDED_FEATURES = {"fast_passage"}

# Features that go at the end (large config sections)
LARGE_FEATURES = {"dynamic-options", "fm-messages", "mute-messages", "pickup-alert", "alert-monsters"}


# =============================================================================
# BRC reference resolution
# =============================================================================

def parse_brc_keys() -> Dict[str, str]:
    """Parse BRC.KEYS = { ... } from constants.lua, returning key -> value_text."""
    text = constants_file.read_text(encoding="utf-8")
    m = re.search(r'BRC\.KEYS\s*=\s*\{([^}]+)\}', text, re.DOTALL)
    if not m:
        return {}
    keys = {}
    for km in re.finditer(r'(?:\["([^"]+)"\]|(\w+))\s*=\s*([^,\n}]+)', m.group(1)):
        name = km.group(1) or km.group(2)
        keys[name] = km.group(3).strip()
    return keys


def parse_brc_constants() -> Dict[str, Dict[str, str]]:
    """Parse simple BRC.X = { k = v, ... } tables from constants.lua."""
    text = constants_file.read_text(encoding="utf-8")
    tables: Dict[str, Dict[str, str]] = {}

    for m in re.finditer(r'BRC\.(\w+)\s*=\s*\{([^}]+)\}', text):
        name = m.group(1)
        entries = {}
        for km in re.finditer(r'(?:\["([^"]+)"\]|(\w+))\s*=\s*([^,\n}]+)', m.group(2)):
            k = km.group(1) or km.group(2)
            entries[k] = km.group(3).strip()
        tables[name] = entries
    return tables


def resolve_brc_refs(text: str, brc_keys: Dict[str, str],
                     brc_tables: Optional[Dict[str, Dict[str, str]]] = None) -> str:
    """Replace BRC.KEYS.X, BRC.COL.x, BRC.DMG_TYPE.x, BRC.util.cntl("X") with literal values."""
    # BRC.KEYS.NAME -> value
    def replace_keys(m):
        name = m.group(1)
        return brc_keys.get(name, m.group(0))

    text = re.sub(r'BRC\.KEYS\.(\w+)', replace_keys, text)
    text = re.sub(r'BRC\.KEYS\["([^"]+)"\]', replace_keys, text)

    # BRC.COL.name -> "name"
    text = re.sub(r'BRC\.COL\.(\w+)', r'"\1"', text)

    # BRC.DMG_TYPE.name -> numeric value
    if brc_tables and 'DMG_TYPE' in brc_tables:
        def replace_dmg_type(m):
            name = m.group(1)
            return brc_tables['DMG_TYPE'].get(name, m.group(0))
        text = re.sub(r'BRC\.DMG_TYPE\.(\w+)', replace_dmg_type, text)

    # BRC.util.cntl("X") -> computed keycode
    def replace_cntl(m):
        char = m.group(1)
        return str(ord(char.upper()) - 64)

    text = re.sub(r'BRC\.util\.cntl\("(\w)"\)', replace_cntl, text)

    return text


# =============================================================================
# Lua text extraction utilities
# =============================================================================

def find_matching_brace(text: str, start: int) -> int:
    """Find position after the matching '}' for a '{' at start."""
    depth = 1
    i = start + 1
    in_str = False
    str_ch = None
    in_cmt = False
    in_blk = False
    in_mlstr = False
    while i < len(text) and depth > 0:
        c = text[i]
        if in_blk:
            if text[i:i+2] == ']]':
                in_blk = False
                i += 2
            else:
                i += 1
            continue
        if in_mlstr:
            if text[i:i+2] == ']]':
                in_mlstr = False
                i += 2
            else:
                i += 1
            continue
        if in_cmt:
            if c == '\n':
                in_cmt = False
            i += 1
            continue
        if in_str:
            if c == '\\':
                i += 2
                continue
            if c == str_ch:
                in_str = False
            i += 1
            continue
        if text[i:i+4] == '--[[':
            in_blk = True
            i += 4
            continue
        if text[i:i+2] == '--':
            in_cmt = True
            i += 2
            continue
        if text[i:i+2] == '[[':
            in_mlstr = True
            i += 2
            continue
        if c in ('"', "'"):
            in_str = True
            str_ch = c
            i += 1
            continue
        if c == '{':
            depth += 1
        elif c == '}':
            depth -= 1
        i += 1
    return i


def find_matching_end(text: str, start: int) -> int:
    """Find position after 'end' matching a function/if/for at start."""
    nest = 1
    i = start
    while i < len(text) and nest > 0:
        # Skip strings
        if text[i] in ('"', "'"):
            q = text[i]
            i += 1
            while i < len(text) and text[i] != q:
                if text[i] == '\\':
                    i += 1
                i += 1
            i += 1
            continue
        # Skip comments
        if text[i:i+2] == '--':
            nl = text.find('\n', i)
            i = nl + 1 if nl != -1 else len(text)
            continue
        # Check keywords at word boundaries
        if i == 0 or not (text[i-1].isalnum() or text[i-1] == '_'):
            for kw in ('function', 'if', 'for', 'while'):
                if text[i:i+len(kw)] == kw:
                    end_pos = i + len(kw)
                    if end_pos >= len(text) or not (text[end_pos].isalnum() or text[end_pos] == '_'):
                        nest += 1
                        break
            if text[i:i+3] == 'end':
                end_pos = i + 3
                if end_pos >= len(text) or not (text[end_pos].isalnum() or text[end_pos] == '_'):
                    nest -= 1
                    if nest == 0:
                        return end_pos
        i += 1
    return i


# =============================================================================
# Config extraction
# =============================================================================

def extract_table_body(text: str, brace_pos: int) -> str:
    """Extract inner content of a { ... } table (without the outer braces)."""
    end = find_matching_brace(text, brace_pos)
    inner = text[brace_pos + 1:end - 1]
    # Strip leading/trailing blank lines but preserve indentation
    lines = inner.split('\n')
    while lines and not lines[0].strip():
        lines.pop(0)
    while lines and not lines[-1].strip():
        lines.pop()
    return '\n'.join(lines)


def extract_function_text(text: str, func_start: int) -> str:
    """Extract function() ... end as complete text."""
    end = find_matching_end(text, func_start + 8)  # skip 'function'
    return text[func_start:end]


ConfigEntry = Tuple[str, str, bool, str]  # (dotted_path, text, is_function, leading_comment)


def extract_leading_comment(text: str, match_start: int) -> str:
    """Extract comment block (-- lines and --[[ ]] blocks) immediately preceding a match position."""
    lines = text[:match_start].split('\n')
    comment_lines = []
    in_block_comment = False
    # Walk backward from the line before the match
    for line in reversed(lines):
        stripped = line.strip()
        if not stripped:
            if comment_lines:
                comment_lines.append('')
            continue
        # Track --[[ ]] block boundaries (walking backward)
        if stripped == '--]]':
            in_block_comment = True
            comment_lines.append(line)
            continue
        if in_block_comment:
            comment_lines.append(line)
            if stripped.startswith('--[['):
                in_block_comment = False
            continue
        if stripped.startswith('--'):
            comment_lines.append(line)
        else:
            break
    if not comment_lines:
        return ''
    comment_lines.reverse()
    # Strip trailing blank lines
    while comment_lines and not comment_lines[-1].strip():
        comment_lines.pop()
    return '\n'.join(comment_lines)


def extract_config_entries(file_path: Path) -> Tuple[Optional[str], Optional[str], List[ConfigEntry]]:
    """Extract config entries from a feature file.

    Returns (feature_name, var_name, entries) where entries is a list of
    (dotted_path, value_text, is_function, leading_comment) tuples.
    """
    text = file_path.read_text(encoding="utf-8")

    # Find feature name and variable name
    m = re.search(r'^(\w+)\.BRC_FEATURE_NAME\s*=\s*["\']([^"\']+)["\']', text, re.MULTILINE)
    if not m:
        return None, None, []
    var_name = m.group(1)
    feature_name = m.group(2)

    entries: List[ConfigEntry] = []
    pattern = re.compile(rf'^{re.escape(var_name)}\.Config\b([\w.]*)\s*=\s*', re.MULTILINE)

    for m in pattern.finditer(text):
        path = m.group(1).lstrip('.')  # e.g., "Tuning.Armour" or ""
        after_eq = m.end()
        rest = text[after_eq:].lstrip()
        leading = extract_leading_comment(text, m.start())

        if rest.startswith('{'):
            brace_pos = text.index('{', after_eq)
            body = extract_table_body(text, brace_pos)
            if not body.strip():
                # Even for empty tables, capture leading comments for parent nodes
                if leading:
                    entries.append((path, '', False, leading))
                continue
            entries.append((path, body, False, leading))
        elif rest.startswith('function'):
            func_start = text.index('function', after_eq)
            func_text = extract_function_text(text, func_start)
            entries.append((path, func_text, True, leading))

    return feature_name, var_name, entries


def extract_config_entries_by_var(file_path: Path, var_name: str) -> List[ConfigEntry]:
    """Extract config entries when var_name is known (e.g., pickup-alert)."""
    text = file_path.read_text(encoding="utf-8")
    entries: List[ConfigEntry] = []
    pattern = re.compile(rf'^{re.escape(var_name)}\.Config\b([\w.]*)\s*=\s*', re.MULTILINE)

    for m in pattern.finditer(text):
        path = m.group(1).lstrip('.')
        after_eq = m.end()
        rest = text[after_eq:].lstrip()
        leading = extract_leading_comment(text, m.start())

        if rest.startswith('{'):
            brace_pos = text.index('{', after_eq)
            body = extract_table_body(text, brace_pos)
            if not body.strip():
                if leading:
                    entries.append((path, '', False, leading))
                continue
            entries.append((path, body, False, leading))
        elif rest.startswith('function'):
            func_start = text.index('function', after_eq)
            func_text = extract_function_text(text, func_start)
            entries.append((path, func_text, True, leading))

    return entries


# =============================================================================
# Nesting reconstruction for multi-assignment configs (e.g., pickup-alert)
# =============================================================================

class ConfigNode:
    """Tree node for reconstructing nested config tables."""

    def __init__(self):
        self.children: Dict[str, 'ConfigNode'] = {}
        self.body: Optional[str] = None
        self.is_function: bool = False
        self.leading_comment: str = ''

    def add(self, path_parts: List[str], body: str, is_function: bool = False,
            leading_comment: str = ''):
        if not path_parts:
            self.body = body
            self.is_function = is_function
            if leading_comment:
                self.leading_comment = leading_comment
            return
        key = path_parts[0]
        if key not in self.children:
            self.children[key] = ConfigNode()
        self.children[key].add(path_parts[1:], body, is_function, leading_comment)

    def _emit_leading_comment(self, lines: List[str], pad: str, comment: str):
        """Emit a leading comment block, re-indented to current level."""
        if not comment:
            return
        lines.append("")  # blank line before comment block
        for line in comment.split('\n'):
            stripped = line.strip()
            if stripped:
                lines.append(pad + stripped)
            else:
                lines.append("")

    def serialize(self, indent: int = 4) -> str:
        """Serialize this node's children as Lua table content lines."""
        pad = ' ' * indent
        lines = []

        # If this node has a body (path="" top-level keys), emit them first
        if self.body and not self.is_function:
            for line in self.body.split('\n'):
                if line.strip():
                    lines.append(pad + line.strip())
                else:
                    lines.append("")

        for key, child in self.children.items():
            # Emit leading comment if present
            if child.leading_comment:
                self._emit_leading_comment(lines, pad, child.leading_comment)

            if child.body and not child.children:
                # Leaf node
                if child.is_function:
                    lines.append(f"{pad}{key} = {child.body},")
                else:
                    lines.append(f"{pad}{key} = {{")
                    for line in child.body.split('\n'):
                        lines.append(f"  {pad}{line.rstrip()}" if line.strip() else "")
                    lines.append(f"{pad}}}, -- {key}")
            elif child.children:
                # Intermediate node with children (may also have a body)
                lines.append(f"{pad}{key} = {{")
                if child.body:
                    for line in child.body.split('\n'):
                        lines.append(f"  {pad}{line.rstrip()}" if line.strip() else "")
                    lines.append("")
                lines.append(child.serialize(indent + 2))
                lines.append(f"{pad}}}, -- {key}")

        return '\n'.join(lines)


def build_nested_body(entries: List[ConfigEntry], base_indent: int = 4) -> str:
    """Build nested Lua table body from config entries."""
    root = ConfigNode()
    for path, body, is_func, leading in entries:
        parts = path.split('.') if path else []
        root.add(parts, body, is_func, leading)
    return root.serialize(base_indent)


# =============================================================================
# Core and hotkey config extraction
# =============================================================================

def extract_core_config() -> str:
    """Extract core config values from config.lua's BRC.Configs.Default."""
    text = config_file.read_text(encoding="utf-8")
    sections = []

    for m in re.finditer(r'^BRC\.Configs\.Default\.(\w+)\s*=\s*', text, re.MULTILINE):
        key = m.group(1)
        if key == "BRC_CONFIG_NAME":
            continue
        after_eq = m.end()
        rest = text[after_eq:].lstrip()

        if rest.startswith('{'):
            brace_pos = text.index('{', after_eq)
            body = extract_table_body(text, brace_pos)
            end = find_matching_brace(text, brace_pos)
            # Get inline comment after closing brace
            rest_line_end = text.find('\n', end)
            rest_of_line = text[end:rest_line_end].strip() if rest_line_end != -1 else ""
            body = dedent_body(body)
            body = indent_body(body, 4)
            body = ensure_brace_comments(body, key)
            # Ensure trailing comma after closing brace
            if rest_of_line and not rest_of_line.startswith(','):
                rest_of_line = ',' + (' ' if rest_of_line else '') + rest_of_line
            elif not rest_of_line:
                rest_of_line = ','
            sections.append(f"  {key} = {{\n{body}\n  }}{rest_of_line}".rstrip())
        else:
            # Simple value — extract to end of line
            eol = text.find('\n', after_eq)
            value = text[after_eq:eol].strip() if eol != -1 else text[after_eq:].strip()
            # Ensure trailing comma
            if not value.endswith(','):
                # Check if there's a comment
                comment_match = re.match(r'([^-]+?)\s*(--.*)', value)
                if comment_match:
                    value = f"{comment_match.group(1).rstrip()}, {comment_match.group(2)}"
                else:
                    value = value.rstrip() + ","
            sections.append(f"  {key} = {value}")

    return '\n\n'.join(sections)


def extract_hotkey_config(brc_keys: Dict[str, str]) -> str:
    """Extract BRC.Hotkey.Config from hotkey.lua."""
    text = hotkey_file.read_text(encoding="utf-8")
    m = re.search(r'BRC\.Hotkey\.Config\s*=\s*\{', text)
    if not m:
        return ""
    brace_pos = text.index('{', m.start())
    body = extract_table_body(text, brace_pos)
    body = resolve_brc_refs(body, brc_keys, None)
    return body


# =============================================================================
# Feature ordering
# =============================================================================

def get_feature_order() -> List[str]:
    """Get feature file order from init.txt."""
    text = init_file.read_text(encoding="utf-8")
    order = []
    for line in text.split('\n'):
        line = line.strip()
        if line.startswith('#'):
            continue
        m = re.match(r'lua_file\s*=\s*crawl-rc/lua/features/(.+\.lua)', line)
        if m:
            order.append(m.group(1))
    return order


# =============================================================================
# Output formatting
# =============================================================================

def indent_body(body: str, spaces: int = 4) -> str:
    """Re-indent a block of text."""
    pad = ' ' * spaces
    lines = []
    for line in body.split('\n'):
        stripped = line.strip()
        if not stripped:
            lines.append("")
        else:
            # Preserve relative indentation from original
            original_indent = len(line) - len(line.lstrip())
            lines.append(pad + ' ' * original_indent + stripped)
    return '\n'.join(lines)


def dedent_body(body: str) -> str:
    """Remove common leading whitespace from a block."""
    lines = body.split('\n')
    non_empty = [l for l in lines if l.strip()]
    if not non_empty:
        return body
    min_indent = min(len(l) - len(l.lstrip()) for l in non_empty)
    return '\n'.join(l[min_indent:] if l.strip() else '' for l in lines)


def ensure_brace_comments(text: str, context: str = "") -> str:
    """Ensure no line has only '}' — add inline comment if needed."""
    lines = text.split('\n')
    for i, line in enumerate(lines):
        if re.match(r'^\s*}\s*$', line):
            lines[i] = line.rstrip() + f' -- {context}'
    return '\n'.join(lines)


def format_feature_section(
    feature_name: str,
    entries: List[ConfigEntry],
    brc_keys: Dict[str, str],
    brc_tables: Dict[str, Dict[str, str]],
    has_disabled: bool,
) -> str:
    """Format a feature's config as a ["feature-name"] = { ... } section."""

    if not entries:
        # Feature with no config — just disabled
        return f'  ["{feature_name}"] = {{\n    disabled = false,\n  }},'

    # Check if this is a simple single-table config or multi-assignment
    is_single = len(entries) == 1 and entries[0][0] == ""

    if is_single:
        body = entries[0][1]
        leading = entries[0][3] if len(entries[0]) > 3 else ''
        body = resolve_brc_refs(body, brc_keys, brc_tables)
        body = dedent_body(body)

        # Add disabled if not present
        if not has_disabled:
            body = "disabled = false,\n" + body

        # Indent to 4 spaces (inside the feature section)
        body = indent_body(body, 4)
        body = ensure_brace_comments(body, feature_name)
        return f'  ["{feature_name}"] = {{\n{body}\n  }},'
    else:
        # Multi-assignment: build nested structure
        resolved = []
        for path, text, is_func, leading in entries:
            resolved_text = resolve_brc_refs(text, brc_keys, brc_tables)
            resolved_text = dedent_body(resolved_text)
            resolved.append((path, resolved_text, is_func, leading))

        nested_body = build_nested_body(resolved)

        # Add disabled at the top
        disabled_line = "    disabled = false,"
        body = f"{disabled_line}\n{nested_body}" if not has_disabled else nested_body
        body = ensure_brace_comments(body, feature_name)
        return f'  ["{feature_name}"] = {{\n{body}\n  }},'


# =============================================================================
# Main
# =============================================================================

def main() -> int:
    brc_keys = parse_brc_keys()
    brc_tables = parse_brc_constants()

    # Collect features in init.txt order
    feature_order = get_feature_order()

    # Map feature files to their paths
    feature_file_map: Dict[str, Path] = {}
    for f in features_dir.glob("*.lua"):
        if f.name == "_template.lua":
            continue
        feature_file_map[f.name] = f

    # Process features in order
    feature_sections_normal: List[str] = []
    feature_sections_large: List[str] = []

    processed = set()
    for lua_file in feature_order:
        # pickup-alert is special: config in pa-config.lua, name in pa-main.lua
        if lua_file.startswith("pickup-alert/"):
            if "pickup-alert" in processed:
                continue
            pa_config = features_dir / "pickup-alert" / "pa-config.lua"
            if not pa_config.exists():
                continue
            feature_name = "pickup-alert"
            entries = extract_config_entries_by_var(pa_config, "f_pickup_alert")
            processed.add("pickup-alert")
        else:
            file_path = feature_file_map.get(lua_file)
            if not file_path:
                continue
            feature_name, var_name, entries = extract_config_entries(file_path)
            if not feature_name:
                continue

        if feature_name in EXCLUDED_FEATURES:
            continue

        processed.add(feature_name)

        # Check if disabled is already in any config entry
        has_disabled = any(
            re.search(r'\bdisabled\s*=', body)
            for _, body, is_func, *_ in entries
            if not is_func
        )

        section = format_feature_section(feature_name, entries, brc_keys, brc_tables, has_disabled)

        if feature_name in LARGE_FEATURES:
            feature_sections_large.append(section)
        else:
            feature_sections_normal.append(section)

    # Build core config section
    core_config = extract_core_config()

    # Build hotkey section
    hotkey_body = extract_hotkey_config(brc_keys)
    hotkey_body = dedent_body(hotkey_body)
    hotkey_body = indent_body(hotkey_body, 4)
    hotkey_body = ensure_brace_comments(hotkey_body, "hotkey")
    hotkey_section = f"  hotkey = {{\n{hotkey_body}\n  }},"

    # Assemble output
    parts = [
        HEADER,
        "brc_config_explicit = {",
        '  BRC_CONFIG_NAME = "Explicit",',
        "",
        "  ---- BRC Core values ----",
        core_config,
        "",
        hotkey_section,
        "",
        "  ---- Feature configs ----",
        '\n\n'.join(feature_sections_normal),
        "",
        "  ---- Large config sections ----",
        '\n\n'.join(feature_sections_large),
        "} -- brc_config_explicit (do not remove this comment)",
    ]

    output = '\n'.join(parts) + '\n'
    output_file.write_text(output, encoding="utf-8")
    print(f"Generated {output_file.relative_to(base_dir)}")
    return 0


if __name__ == "__main__":
    sys.exit(main())
